exercise.solution_code:
#include <iostream>
#include <string>

namespace {
    std::string classifyLinkage(char kind) {
        if (kind == 's') return "internal (static)";
        else if (kind == 'a') return "internal (anonymous namespace)";
        else if (kind == 'c') return "internal (const default)";
        else if (kind == 'e') return "external";
        else return "unknown";
    }
}

int main() {
    char k1{}, k2{}, k3{}, k4{};
    std::cin >> k1 >> k2 >> k3 >> k4;

    std::cout << classifyLinkage(k1) << '\n';
    std::cout << classifyLinkage(k2) << '\n';
    std::cout << classifyLinkage(k3) << '\n';
    std::cout << classifyLinkage(k4) << '\n';

    return 0;
}
